import{_ as r,G as p,c as o,o as n,j as e,J as s,a6 as i,a as d}from"./chunks/framework.D3uGTwuV.js";const f=JSON.parse('{"title":"[GitHub]JM&哔咔第三方客户端(解决旧版客户端任何烦恼)","description":"","frontmatter":{},"headers":[],"relativePath":"GitHub项目推荐/JM&哔咔第三方客户端.md","filePath":"GitHub项目推荐/JM&哔咔第三方客户端.md","lastUpdated":1775109753000}'),l={name:"GitHub项目推荐/JM&哔咔第三方客户端.md"};function _(b,a,c,h,g,u){const t=p("ArticleMetadata");return n(),o("div",{"data-pagefind-body":!0,"data-pagefind-meta":"date:1775109753000"},[a[0]||(a[0]=e("h1",{id:"github-jm-哔咔第三方客户端-解决旧版客户端任何烦恼",tabindex:"-1"},[d("[GitHub]JM&哔咔第三方客户端(解决旧版客户端任何烦恼) "),e("a",{class:"header-anchor",href:"#github-jm-哔咔第三方客户端-解决旧版客户端任何烦恼","aria-label":"Permalink to “[GitHub]JM&哔咔第三方客户端(解决旧版客户端任何烦恼)”"},"​")],-1)),s(t),a[1]||(a[1]=i('<p>下载链接放结尾了</p><p>用过原版客户端的肯定见识到了什么叫难用，如图：</p><p><img src="https://cdn.nlark.com/yuque/0/2026/jpeg/42939896/1769648089978-4e488b07-f946-49a1-9b34-25fe54285d82.jpeg" alt=""></p><p>穿插在各种页面的广告闪瞎眼，图片加载老半天说是看本子还不如说是看着禁漫娘起飞，想下载到本地还得做小学数学题，起飞时长几个小时直接阳痿</p><h2 id="_1、介绍" tabindex="-1">1、介绍 <a class="header-anchor" href="#_1、介绍" aria-label="Permalink to “1、介绍”">​</a></h2><p>回归正题，最近我在GitHub挖到这个<strong>Breeze</strong> —— 直接破了官方所有槽点，flutter写的第三方客户端，把JM和哔咔整到一个App里，简直爽爆了</p><p>Breeze 是哔咔(PicACG/bika)与禁漫（禁漫天堂，jm）的第三方安卓客户端，采用 Flutter 开发</p><h2 id="_2、这app牛在哪" tabindex="-1">2、这App牛在哪？ <a class="header-anchor" href="#_2、这app牛在哪" aria-label="Permalink to “2、这App牛在哪？”">​</a></h2><p><strong>零广告，真干净</strong><br> 开屏直接进，阅读中途零弹窗，再也不用看&quot;同城约X&quot;了</p><p><strong>速度起飞</strong><br> 图片预加载做得比官方好太多，流畅的一批（其实也就是取决于你的梯子和机场性能）</p><p><strong>下载自由</strong><br> 支持批量下载漫画，还能导出成ZIP存本地，再也不用做数学题了</p><p><strong>双平台合一</strong><br> 一个App同时登录JM和哔咔，不用来回切了，直接享受双倍快乐</p><p><strong>自动签到</strong><br> 自动签到功能，每天打开自动领积分</p><p><strong>Modern UI</strong><br> 有暗黑模式，晚上看不伤眼</p><p><strong>闪退</strong></p><p>解决JM老是动不动就闪退的老毛病，并且加载不成功时可以多试几遍，一般不超过5遍就可以看了</p><h2 id="_3、缺点" tabindex="-1">3、缺点 <a class="header-anchor" href="#_3、缺点" aria-label="Permalink to “3、缺点”">​</a></h2><p>本人亲自试毒</p><p><strong>收藏点赞要得多点几次</strong><br> 不知道是不是接口问题，有时候点收藏或点赞，明明显示成功了，退出去再进发现没点上。我现在养成了点两次的习惯 —— 点一下，等两秒，取消再点一下，这样比较稳。希望作者后续能优化下这个接口同步</p><p><strong>对梯子质量有要求</strong><br> 虽然比官方流畅，但如果你梯子节点太拉胯，还是会报错或者图片加载到一半卡住失败。我试过用某些免费节点，时不时跳出&quot;网络错误&quot;，换成付费稳一点的线就没事，最好还是用机场</p><blockquote><p>不过也没太多不好用的地方解决屏蔽广告已经是我最大的愿望了，如果遇到了可以说一下</p></blockquote><h2 id="_4、展示" tabindex="-1">4、展示 <a class="header-anchor" href="#_4、展示" aria-label="Permalink to “4、展示”">​</a></h2><p>其实也没啥能展示的，都马赛克，看个大概就行（希望不要被审核办了）</p><p><img src="https://cdn.nlark.com/yuque/0/2026/jpeg/42939896/1769650654524-34948543-5a20-41f4-b433-155b17af0c22.jpeg" alt=""></p><h2 id="_5、结尾总结" tabindex="-1">5、结尾总结 <a class="header-anchor" href="#_5、结尾总结" aria-label="Permalink to “5、结尾总结”">​</a></h2><p>如果你每天都在被官方App的广告 闪退和卡顿折磨，直接换这个就完事了，作者还在持续更新维护</p><p>觉得好用记得回GitHub给作者点个Star，开源项目不容易</p><h2 id="_6、下载" tabindex="-1">6、下载 <a class="header-anchor" href="#_6、下载" aria-label="Permalink to “6、下载”">​</a></h2>',28))])}const k=r(l,[["render",_]]);export{f as __pageData,k as default};
